import{_ as s,c as t,o as a,a1 as e}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"Быстрый старт: за 5 минут освоить opencode-notify | Руководство по opencode-notify","description":"Узнайте, как установить плагин opencode-notify, настроить его за 5 минут и протестировать первое уведомление на рабочем столе. Это руководство охватывает два способа установки — через пакетный менеджер OCX и ручную установку, поддерживает системы macOS, Windows и Linux, помогая вам вовремя получать уведомления при завершении AI-задач.","frontmatter":{"title":"Быстрый старт: за 5 минут освоить opencode-notify | Руководство по opencode-notify","sidebarTitle":"Уведомление за 5 минут","subtitle":"Быстрый старт: за 5 минут освоить opencode-notify","description":"Узнайте, как установить плагин opencode-notify, настроить его за 5 минут и протестировать первое уведомление на рабочем столе. Это руководство охватывает два способа установки — через пакетный менеджер OCX и ручную установку, поддерживает системы macOS, Windows и Linux, помогая вам вовремя получать уведомления при завершении AI-задач.","tags":["Введение","Установка","Быстрый старт"],"prerequisite":[],"order":10},"headers":[],"relativePath":"ru/kdcokenny/opencode-notify/start/quick-start/index.md","filePath":"ru/kdcokenny/opencode-notify/start/quick-start/index.md"}'),n={name:"ru/kdcokenny/opencode-notify/start/quick-start/index.md"};function o(l,i,d,r,h,p){return a(),t("div",null,[...i[0]||(i[0]=[e(`<h1 id="быстрыи-старт-за-5-минут-освоить-opencode-notify" tabindex="-1">Быстрый старт: за 5 минут освоить opencode-notify <a class="header-anchor" href="#быстрыи-старт-за-5-минут-освоить-opencode-notify" aria-label="Permalink to &quot;Быстрый старт: за 5 минут освоить opencode-notify&quot;">​</a></h1><h2 id="что-вы-сможете-делать-после-этого-урока" tabindex="-1">Что вы сможете делать после этого урока <a class="header-anchor" href="#что-вы-сможете-делать-после-этого-урока" aria-label="Permalink to &quot;Что вы сможете делать после этого урока&quot;">​</a></h2><ul><li>Установить плагин opencode-notify за 3 минуты</li><li>Триггернуть первое уведомление на рабочем столе и подтвердить успешную установку</li><li>Понять различия между разными способами установки и их применимость</li></ul><h2 id="ваша-текущая-ситуация" tabindex="-1">Ваша текущая ситуация <a class="header-anchor" href="#ваша-текущая-ситуация" aria-label="Permalink to &quot;Ваша текущая ситуация&quot;">​</a></h2><p>Вы поручили AI выполнить задачу и переключились на другие окна. Теперь каждые 30 секунд вы переключаетесь обратно, чтобы проверить: готово ли? Ошибка? Или ждёт разрешения? opencode-notify создан именно для решения этой проблемы.</p><p>Это постоянное переключение прерывает ваше мышление и тратит время.</p><h2 id="когда-использовать-этот-подход" tabindex="-1">Когда использовать этот подход <a class="header-anchor" href="#когда-использовать-этот-подход" aria-label="Permalink to &quot;Когда использовать этот подход&quot;">​</a></h2><p><strong>Включите opencode-notify в следующих сценариях</strong>:</p><ul><li>Вы часто переключаетесь на другие приложения, пока AI выполняет задачу</li><li>Вы хотите быть немедленно уведомлены, когда AI нуждается в вас</li><li>Вы хотите сохранять концентрацию, не упуская важные события</li></ul><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Принцип работы opencode-notify прост: слушать события OpenCode и отправлять нативные уведомления на рабочий стол в ключевые моменты.</p><p><strong>Он уведомит вас о</strong>:</p><ul><li>✅ Завершении задачи (Session idle)</li><li>✅ Ошибке выполнения (Session error)</li><li>✅ Необходимости разрешения (Permission updated)</li></ul><p><strong>Он не будет уведомлять вас о</strong>:</p><ul><li>❌ Завершении каждой подзадачи (слишком шумно)</li><li>❌ Любых событиях при фокусе терминала (вы смотрите на терминал, уведомление не нужно)</li></ul><h2 id="🎒-подготовка-перед-началом" tabindex="-1">🎒 Подготовка перед началом <a class="header-anchor" href="#🎒-подготовка-перед-началом" aria-label="Permalink to &quot;🎒 Подготовка перед началом&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Требования</p><ul><li>Установлен <a href="https://github.com/sst/opencode" target="_blank" rel="noreferrer">OpenCode</a></li><li>Доступный терминал (macOS Terminal, iTerm2, Windows Terminal и т.д.)</li><li>Система macOS/Windows/Linux (все три поддерживаются)</li></ul></div><h2 id="следуите-за-мнои" tabindex="-1">Следуйте за мной <a class="header-anchor" href="#следуите-за-мнои" aria-label="Permalink to &quot;Следуйте за мной&quot;">​</a></h2><h3 id="шаг-1-выберите-способ-установки" tabindex="-1">Шаг 1: Выберите способ установки <a class="header-anchor" href="#шаг-1-выберите-способ-установки" aria-label="Permalink to &quot;Шаг 1: Выберите способ установки&quot;">​</a></h3><p>opencode-notify предлагает два способа установки:</p><table tabindex="0"><thead><tr><th>Способ</th><th>Применимость</th><th>Преимущества</th><th>Недостатки</th></tr></thead><tbody><tr><td><strong>Пакетный менеджер OCX</strong></td><td>Большинство пользователей</td><td>Установка в один клик, автоматические обновления, полное управление зависимостями</td><td>Требуется предварительная установка OCX</td></tr><tr><td><strong>Ручная установка</strong></td><td>Особые требования</td><td>Полный контроль, не требует OCX</td><td>Необходимо вручную управлять зависимостями и обновлениями</td></tr></tbody></table><p><strong>Рекомендация</strong>: Используйте OCX для установки — проще и удобнее.</p><h3 id="шаг-2-установка-через-ocx-рекомендуется" tabindex="-1">Шаг 2: Установка через OCX (рекомендуется) <a class="header-anchor" href="#шаг-2-установка-через-ocx-рекомендуется" aria-label="Permalink to &quot;Шаг 2: Установка через OCX (рекомендуется)&quot;">​</a></h3><h4 id="_2-1-установка-пакетного-менеджера-ocx" tabindex="-1">2.1 Установка пакетного менеджера OCX <a class="header-anchor" href="#_2-1-установка-пакетного-менеджера-ocx" aria-label="Permalink to &quot;2.1 Установка пакетного менеджера OCX&quot;">​</a></h4><p>OCX — официальный пакетный менеджер плагинов для OpenCode, позволяющий легко устанавливать, обновлять и управлять плагинами.</p><p><strong>Установка OCX</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://ocx.kdco.dev/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>: Скрипт установки отображает прогресс и в конце сообщает об успешной установке.</p><h4 id="_2-2-добавление-kdco-registry" tabindex="-1">2.2 Добавление KDCO Registry <a class="header-anchor" href="#_2-2-добавление-kdco-registry" aria-label="Permalink to &quot;2.2 Добавление KDCO Registry&quot;">​</a></h4><p>KDCO Registry — репозиторий плагинов, содержащий opencode-notify и множество других полезных плагинов.</p><p><strong>Добавление registry</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://registry.kdco.dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>: Сообщение &quot;Registry added successfully&quot; или аналогичное.</p><div class="tip custom-block"><p class="custom-block-title">Опционально: глобальная конфигурация</p><p>Если вы хотите использовать один и тот же registry во всех проектах, добавьте параметр <code>--global</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://registry.kdco.dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span></span></code></pre></div></div><h4 id="_2-3-установка-opencode-notify" tabindex="-1">2.3 Установка opencode-notify <a class="header-anchor" href="#_2-3-установка-opencode-notify" aria-label="Permalink to &quot;2.3 Установка opencode-notify&quot;">​</a></h4><p><strong>Установка плагина</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco/notify</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ Added kdco/notify to your OpenCode workspace</span></span></code></pre></div><h3 id="шаг-3-установка-всего-рабочего-пространства-однои-командои-опционально" tabindex="-1">Шаг 3: Установка всего рабочего пространства одной командой (опционально) <a class="header-anchor" href="#шаг-3-установка-всего-рабочего-пространства-однои-командои-опционально" aria-label="Permalink to &quot;Шаг 3: Установка всего рабочего пространства одной командой (опционально)&quot;">​</a></h3><p>Если вы хотите получить полный опыт, вы можете установить рабочее пространство KDCO, которое включает:</p><ul><li>opencode-notify (уведомления на рабочем столе)</li><li>Фоновые агенты (Background Agents)</li><li>Специализированные агенты (Specialist Agents)</li><li>Инструменты планирования (Planning Tools)</li></ul><p><strong>Установка рабочего пространства</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco/workspace</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>: Сообщение о том, что несколько компонентов были успешно добавлены.</p><h3 id="шаг-4-проверка-установки" tabindex="-1">Шаг 4: Проверка установки <a class="header-anchor" href="#шаг-4-проверка-установки" aria-label="Permalink to &quot;Шаг 4: Проверка установки&quot;">​</a></h3><p>После завершения установки нам нужно вызвать уведомление, чтобы проверить правильность конфигурации.</p><p><strong>Метод проверки 1: Дать AI задачу на выполнение</strong></p><p>В OpenCode введите:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Пожалуйста, вычислите сумму чисел от 1 до 10, а затем подождите 5 секунд и сообщите результат.</span></span></code></pre></div><p>Переключитесь на другие окна и поработайте несколько секунд, затем вы должны увидеть всплывающее уведомление на рабочем столе.</p><p><strong>Метод проверки 2: Проверка конфигурационного файла</strong></p><p>Проверьте, существует ли файл конфигурации:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS/Linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/kdco-notify.json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows PowerShell</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:USERPROFILE</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pencode</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dco-notify.json</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>:</p><ul><li>Если файл не существует → используются настройки по умолчанию (нормально)</li><li>Если файл существует → отображается ваша пользовательская конфигурация</li></ul><h3 id="шаг-5-ручная-установка-альтернативныи-вариант" tabindex="-1">Шаг 5: Ручная установка (альтернативный вариант) <a class="header-anchor" href="#шаг-5-ручная-установка-альтернативныи-вариант" aria-label="Permalink to &quot;Шаг 5: Ручная установка (альтернативный вариант)&quot;">​</a></h3><p>Если вы не хотите использовать OCX, вы можете установить вручную.</p><h4 id="_5-1-копирование-исходного-кода" tabindex="-1">5.1 Копирование исходного кода <a class="header-anchor" href="#_5-1-копирование-исходного-кода" aria-label="Permalink to &quot;5.1 Копирование исходного кода&quot;">​</a></h4><p>Скопируйте исходный код opencode-notify в каталог плагинов OpenCode:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Копирование из исходников в отдельный каталог</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/kdco-notify</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/notify.ts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/kdco-notify/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/plugin/kdco-primitives</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/kdco-notify/</span></span></code></pre></div><h4 id="_5-2-установка-зависимостеи" tabindex="-1">5.2 Установка зависимостей <a class="header-anchor" href="#_5-2-установка-зависимостеи" aria-label="Permalink to &quot;5.2 Установка зависимостей&quot;">​</a></h4><p>Установите необходимые зависимости вручную:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node-notifier</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> detect-terminal</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @opencode-ai/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @opencode-ai/sdk</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Важные замечания</p><ul><li><strong>Управление зависимостями</strong>: необходимо вручную устанавливать и обновлять <code>node-notifier</code> и <code>detect-terminal</code></li><li><strong>Сложность обновления</strong>: каждое обновление требует ручного копирования исходного кода</li><li><strong>Не рекомендуется</strong>: если нет особых требований, рекомендуется использовать установку через OCX</li></ul></div><h3 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h3><p>После завершения описанных выше шагов, пожалуйста, подтвердите:</p><ul><li>[ ] OCX успешно установлен (<code>ocx --version</code> выводит номер версии)</li><li>[ ] KDCO Registry добавлен (<code>ocx registry list</code> отображает kdco)</li><li>[ ] opencode-notify установлен (<code>ocx list</code> отображает kdco/notify)</li><li>[ ] Получено первое уведомление на рабочем столе</li><li>[ ] Уведомление отображает правильный заголовок задачи</li></ul><p><strong>Если какой-либо шаг не удался</strong>:</p><ul><li>Посмотрите раздел <a href="./../../faq/troubleshooting/">Устранение неполадок</a> для получения помощи</li><li>Проверьте, работает ли OpenCode нормально</li><li>Убедитесь, что ваша система поддерживает уведомления на рабочем столе</li></ul><h2 id="возможные-проблемы" tabindex="-1">Возможные проблемы <a class="header-anchor" href="#возможные-проблемы" aria-label="Permalink to &quot;Возможные проблемы&quot;">​</a></h2><h3 id="проблема-1-уведомления-не-отображаются" tabindex="-1">Проблема 1: Уведомления не отображаются <a class="header-anchor" href="#проблема-1-уведомления-не-отображаются" aria-label="Permalink to &quot;Проблема 1: Уведомления не отображаются&quot;">​</a></h3><p><strong>Причина</strong>:</p><ul><li>macOS: системные уведомления отключены</li><li>Windows: разрешение на уведомления не предоставлено</li><li>Linux: notify-send не установлен</li></ul><p><strong>Решение</strong>:</p><table tabindex="0"><thead><tr><th>Платформа</th><th>Решение</th></tr></thead><tbody><tr><td>macOS</td><td>Системные настройки → Уведомления → OpenCode → Разрешить уведомления</td></tr><tr><td>Windows</td><td>Параметры → Система → Уведомления → Включить уведомления</td></tr><tr><td>Linux</td><td>Установить libnotify-bin: <code>sudo apt install libnotify-bin</code></td></tr></tbody></table><h3 id="проблема-2-ошибка-установки-ocx" tabindex="-1">Проблема 2: Ошибка установки OCX <a class="header-anchor" href="#проблема-2-ошибка-установки-ocx" aria-label="Permalink to &quot;Проблема 2: Ошибка установки OCX&quot;">​</a></h3><p><strong>Причина</strong>: Проблемы с сетью или недостаточно прав</p><p><strong>Решение</strong>:</p><ol><li>Проверьте сетевое подключение</li><li>Используйте sudo для установки (требуются права администратора)</li><li>Загрузите скрипт установки вручную и выполните его</li></ol><h3 id="проблема-3-ошибка-установки-зависимостеи" tabindex="-1">Проблема 3: Ошибка установки зависимостей <a class="header-anchor" href="#проблема-3-ошибка-установки-зависимостеи" aria-label="Permalink to &quot;Проблема 3: Ошибка установки зависимостей&quot;">​</a></h3><p><strong>Причина</strong>: Несовместимая версия Node.js</p><p><strong>Решение</strong>:</p><ul><li>Используйте Node.js версии 18 или выше</li><li>Очистите кэш npm: <code>npm cache clean --force</code></li></ul><h2 id="резюме-урока" tabindex="-1">Резюме урока <a class="header-anchor" href="#резюме-урока" aria-label="Permalink to &quot;Резюме урока&quot;">​</a></h2><p>В этом уроке мы выполнили:</p><ul><li>✅ Установку пакетного менеджера OCX</li><li>✅ Добавление KDCO Registry</li><li>✅ Установку плагина opencode-notify</li><li>✅ Получение первого уведомления на рабочем столе</li><li>✅ Изучение метода ручной установки</li></ul><p><strong>Ключевые моменты</strong>:</p><ol><li>opencode-notify использует нативные уведомления на рабочем столе, нет необходимости часто переключать окна</li><li>OCX — рекомендуемый способ установки, автоматически управляет зависимостями и обновлениями</li><li>По умолчанию уведомляются только родительские сессии, избегая шума от подзадач</li><li>Уведомления автоматически подавляются, когда терминал в фокусе</li></ol><h2 id="следующии-урок" tabindex="-1">Следующий урок <a class="header-anchor" href="#следующии-урок" aria-label="Permalink to &quot;Следующий урок&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../how-it-works/">Как это работает</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как плагин прослушивает события OpenCode</li><li>Рабочий процесс механизма интеллектуальной фильтрации</li><li>Принцип обнаружения терминала и фокусировки</li><li>Различия в функциональности на разных платформах</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть и посмотреть расположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Главный вход плагина</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L1-L407" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>1-407</td></tr><tr><td>Загрузка конфигурации</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L90-L114" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>90-114</td></tr><tr><td>Отправка уведомлений</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L280-L308" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>280-308</td></tr><tr><td>Обнаружение терминала</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L145-L176" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>145-176</td></tr><tr><td>Проверка тихих часов</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L181-L199" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>181-199</td></tr><tr><td>Конфигурация по умолчанию</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L30-L48" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>30-48</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>DEFAULT_CONFIG.sounds.idle = &quot;Glass&quot;</code>: звук по умолчанию при завершении задачи</li><li><code>DEFAULT_CONFIG.sounds.error = &quot;Basso&quot;</code>: звук по умолчанию при ошибке</li><li><code>DEFAULT_CONFIG.sounds.permission = &quot;Submarine&quot;</code>: звук по умолчанию при запросе разрешения</li><li><code>DEFAULT_CONFIG.notifyChildSessions = false</code>: по умолчанию уведомляются только родительские сессии</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>NotifyPlugin()</code>: входная функция плагина, возвращает обработчик событий</li><li><code>loadConfig()</code>: загружает файл конфигурации, объединяет с значениями по умолчанию</li><li><code>sendNotification()</code>: отправляет нативное уведомление на рабочий стол</li><li><code>detectTerminalInfo()</code>: обнаруживает тип терминала и Bundle ID</li><li><code>isQuietHours()</code>: проверяет, находится ли текущее время в тихих часах</li><li><code>isParentSession()</code>: определяет, является ли сессия родительской</li><li><code>isTerminalFocused()</code>: обнаруживает, находится ли терминал на переднем плане</li></ul></details>`,94)])])}const g=s(n,[["render",o]]);export{k as __pageData,g as default};
